			if (current === "*" && next === "/") {
				blockComment = false;
				index += 1;
			}
			continue;
		}

		if (quote) {
			if (escaped) {
				escaped = false;
			} else if (current === "\\") {
				escaped = true;
			} else if (current === quote) {
				quote = undefined;
			}
			continue;
		}

		if (current === "/" && next === "/") {
			lineComment = true;
			index += 1;
			continue;
		}

		if (current === "/" && next === "*") {
			blockComment = true;
			index += 1;
			continue;
		}

		if (current === '"' || current === "'" || current === "`") {
			quote = current;
			continue;
		}

		if (current === "[") {
			depth += 1;
